  "id": "pulseboard",
  "name": "PulseBoard",
  "description": "PulseBoard channel plugin for real-time team notifications",
  "version": "1.0.0",
  "channels": ["pulseboard"],
  "enabledByDefault": true,
  "configSchema": {
    "type": "object",
    "additionalProperties": false,
    "properties": {
      "apiKey": { "type": "string" },
      "workspaceId": { "type": "string" }
    }
  },
  "uiHints": {
    "apiKey": {
      "label": "API Key",
      "placeholder": "pb_...",
      "sensitive": true,
      "help": "Your PulseBoard API key"
    },
    "workspaceId": {
      "label": "Workspace ID",
      "help": "PulseBoard workspace identifier"
    }
  },
  "providerAuthEnvVars": {
    "pulseboard": ["PULSEBOARD_API_KEY"]
  },
  "providerAuthChoices": [
    {
      "provider": "pulseboard",
      "method": "api-key",
      "choiceId": "pulseboard-api-key",
      "choiceLabel": "PulseBoard API Key",
      "groupId": "pulseboard",
      "groupLabel": "PulseBoard",
      "optionKey": "apiKey",
      "cliFlag": "--pulseboard-api-key",
      "cliOption": "--pulseboard-api-key <key>",
      "cliDescription": "PulseBoard API key for authentication",
      "onboardingScopes": ["text-inference"]
    }
  ],
  "contracts": {
    "tools": ["pulseboard_send_notification"]
  }
}
```

**Top-Level Fields Reference:**

| Field | Required | Type | Purpose |
|-------|----------|------|---------|
| `id` | Yes | `string` | Canonical plugin ID (used in config as `plugins.entries.<id>`) |
| `channels` | No | `string[]` | Channel IDs owned by this plugin |
| `configSchema` | Yes | `object` | JSON Schema for plugin config validation |
| `enabledByDefault` | No | `true` | Marks plugin as auto-enabled (bundled plugins only) |
| `name` | No | `string` | Human-readable plugin name |
| `description` | No | `string` | Short summary |
| `version` | No | `string` | Informational version |
| `uiHints` | No | `Record<string, object>` | UI labels, placeholders, sensitivity hints |
| `providerAuthEnvVars` | No | `Record<string, string[]>` | Env vars for provider auth without booting plugin |
| `providerAuthChoices` | No | `object[]` | Onboarding/auth metadata |
| `contracts` | No | `object` | Static capability ownership (tools, providers, etc.) |

---

## 2. SDK CORE CONTRACTS

### A. Channel Plugin Entry Point
**File:** `src/plugin-sdk/core.ts`

**Main Entry Helper - `defineChannelPluginEntry()`:**
```typescript
export function defineChannelPluginEntry<TPlugin>({
  id,
  name,
  description,
  plugin,
  configSchema = emptyPluginConfigSchema,
  setRuntime,
  registerCliMetadata,
  registerFull,
}: DefineChannelPluginEntryOptions<TPlugin>): DefinedChannelPluginEntry<TPlugin>
```

**Key Features:**
- Registers channel capability with OpenClaw runtime
- Handles both setup-only and full runtime registration modes
- Returns object with `{ id, name, description, configSchema, register, channelPlugin }`

### B. Chat Channel Plugin Builder - `createChatChannelPlugin()`
**High-level wrapper** for standard chat-style channels (Slack, Discord, etc.)

```typescript
export function createChatChannelPlugin<TResolvedAccount>({
  base: ChatChannelPluginBase,
  security?: ChatChannelSecurityOptions | ChannelSecurityAdapter,
  pairing?: ChatChannelPairingOptions | ChannelPairingAdapter,
  threading?: ChannelThreadingOptions | ChannelThreadingAdapter,
  outbound?: ChatChannelAttachedOutboundOptions | ChannelOutboundAdapter,
}): ChannelPlugin
```

**Composed from:**
- DM security policies (with allowlist support)
- Text-based pairing/approval
- Reply-to threading modes
- Attached send results (channel names auto-filled)

### C. Channel Plugin Base - `createChannelPluginBase()`
**Lower-level builder** for channels that only override optional surfaces

```typescript
export function createChannelPluginBase<TResolvedAccount>(params: {
  id: string;
  meta?: Partial<ChannelMeta>;
  setup: NonNullable<ChannelPlugin['setup']>;
  setupWizard?: ChannelPlugin['setupWizard'];
  capabilities?: ChannelCapabilities;
  agentPrompt?: ChannelAgentPromptAdapter;
  streaming?: ChannelStreamingAdapter;
  reload?: ChannelPlugin['reload'];
  gatewayMethods?: string[];
  configSchema?: ChannelPlugin['configSchema'];
  config?: ChannelPlugin['config'];
  security?: ChannelSecurityAdapter;
  groups?: ChannelGroupAdapter;
}): CreatedChannelPluginBase
```

---

## 3. CHANNEL PLUGIN INTERFACE (ChannelPlugin Type)

**File:** `src/channels/plugins/types.plugin.ts`

**Complete ChannelPlugin<ResolvedAccount, Probe, Audit> Structure:**

```typescript
export type ChannelPlugin<ResolvedAccount = any, Probe = unknown, Audit = unknown> = {
  id: ChannelId;                                          // Required: plugin ID
  meta: ChannelMeta;                                      // Required: metadata
  capabilities: ChannelCapabilities;                      // Required: capability flags
  defaults?: { queue?: { debounceMs?: number } };
  reload?: { configPrefixes: string[]; noopPrefixes?: string[] };
  setupWizard?: ChannelPluginSetupWizard;                // Interactive setup UI
  config: ChannelConfigAdapter<ResolvedAccount>;         // Required: config resolver
  configSchema?: ChannelConfigSchema;                    // JSON schema + UI hints
  setup?: ChannelSetupAdapter;                           // Account onboarding
  pairing?: ChannelPairingAdapter;                       // User approval/pairing
  security?: ChannelSecurityAdapter<ResolvedAccount>;    // DM policies
  groups?: ChannelGroupAdapter;                          // Group chat helpers
  mentions?: ChannelMentionAdapter;                      // @mention handling
  outbound?: ChannelOutboundAdapter;                     // Send messages/media/polls
  status?: ChannelStatusAdapter<ResolvedAccount, Probe, Audit>;  // Health checks
  gatewayMethods?: string[];                             // HTTP/gateway endpoints
  gateway?: ChannelGatewayAdapter<ResolvedAccount>;      // Gateway handler context
  auth?: ChannelAuthAdapter;                             // Token management
  approvalCapability?: ChannelApprovalCapability;        // Code/action approval
  elevated?: ChannelElevatedAdapter;                     // Admin mode
  commands?: ChannelCommandAdapter;                      // Native commands
  lifecycle?: ChannelLifecycleAdapter;                   // Startup/shutdown
  approvals?: ChannelApprovalAdapter;                    // Approval workflow
  allowlist?: ChannelAllowlistAdapter;                   // Route allowlists
  bindings?: ChannelConfiguredBindingProvider;           // Config bindings
  conversationBindings?: ChannelConversationBindingSupport;
  streaming?: ChannelStreamingAdapter;                   // Real-time events
  threading?: ChannelThreadingAdapter;                   // Thread reply modes
  messaging?: ChannelMessagingAdapter;                   // Target resolution
  agentPrompt?: ChannelAgentPromptAdapter;               // Agent context
  directory?: ChannelDirectoryAdapter;                   // User/group listing
  resolver?: ChannelResolverAdapter;                     // Target resolution
  actions?: ChannelMessageActionAdapter;                 // Message actions
  heartbeat?: ChannelHeartbeatAdapter;                   // Periodic health
  agentTools?: ChannelAgentToolFactory | ChannelAgentTool[]; // Plugin tools
};
```

**Key Generic Parameters:**
- `ResolvedAccount`: Your resolved account type (e.g., `{ accountId: string; botToken: string }`)
- `Probe`: Optional health-check probe result type
- `Audit`: Optional audit trail type

---

## 4. ESSENTIAL CHANNEL ADAPTERS

### A. Configuration Adapter (Required)
```typescript
type ChannelConfigAdapter<ResolvedAccount> = {
  resolveAccount: (cfg: OpenClawConfig, accountId?: string | null) => ResolvedAccount;
  formatAllowFrom?: (params: { ... }) => string | string[];
};
```

### B. Capabilities Adapter (Required)
```typescript
type ChannelCapabilities = {
  directMessages: boolean;
  groups: boolean;
  channels: boolean;
  broadcasts: boolean;
  reactions: boolean;
  threads: boolean;
  messageActions: boolean;
  structuredReplyPayload: boolean;
  media: {
    images: boolean;
    files: boolean;
    audio: boolean;
    video: boolean;
  };
  mentions: "none" | "users" | "groups" | "all";
  groupMentions: boolean;
  messageSigning: boolean;
  commandGating: boolean;
};
```

### C. Setup Adapter (Optional)
```typescript
type ChannelSetupAdapter = {
  resolveAccountId?: (input: ChannelSetupInput) => string | null;
  validate?: (cfg: OpenClawConfig, accountId?: string) => string | null;
  patch?: (cfg: OpenClawConfig, input: ChannelSetupInput) => Partial<OpenClawConfig>;
};
```

### D. Outbound Adapter (Optional)
```typescript
type ChannelOutboundAdapter = {
  resolveOutboundSessionRoute?: (params: {
    cfg: OpenClawConfig;
    agentId: string;
    accountId?: string | null;
    target: string;
    replyToId?: string | null;
    threadId?: string | number | null;
  }) => ChannelOutboundSessionRoute | null | Promise<...>;

  sendText?: (ctx: ChannelOutboundContext) => Promise<OutboundDeliveryResult>;
  sendMedia?: (ctx: ChannelOutboundContext) => Promise<OutboundDeliveryResult>;
  sendPoll?: (ctx: ChannelOutboundContext) => Promise<ChannelPollResult>;
};
```

### E. Messaging Adapter (Optional)
```typescript
type ChannelMessagingAdapter = {
  normalizeTarget: (raw: string) => string;
  parseExplicitTarget?: (raw: string) => { to: string; chatType: string } | null;
  inferTargetChatType?: (to: string) => "direct" | "group" | "channel" | null;
  resolveSessionTarget?: (id: string) => string;
  resolveOutboundSessionRoute: (params) => ChannelOutboundSessionRoute;
};
```

### F. Threading Adapter (Optional)
```typescript
type ChannelThreadingAdapter = {
  resolveReplyToMode: (params: {
    cfg: OpenClawConfig;
    accountId?: string | null;
    chatType?: string | null;
  }) => ReplyToMode | null;
  normalizeThreadId?: (raw: string | number) => string | null;
};
```

### G. Security Adapter (Optional)
```typescript
type ChannelSecurityAdapter<ResolvedAccount> = {
  resolveDmPolicy?: (params: {
    cfg: OpenClawConfig;
    accountId?: string | null;
    account: ResolvedAccount;
  }) => ChannelSecurityDmPolicy | null;
  collectWarnings?: (params) => ChannelStatusIssue[];
};
```

