32	export function parsePort(raw: string, fallback: number): number {
33	  const trimmed = raw.trim();
34	  if (!trimmed) {
35	    return fallback;
36	  }
37	  const parsed = Number.parseInt(trimmed, 10);
38	  if (!Number.isFinite(parsed) || parsed < 1 || parsed > 65535) {
39	    return fallback;
40	  }
41	  return parsed;
42	}
43	
44	export function updateIrcAccountConfig(
45	  cfg: CoreConfig,
46	  accountId: string,
47	  patch: Partial<IrcAccountConfig>,
48	): CoreConfig {
49	  return patchScopedAccountConfig({
50	    cfg,
51	    channelKey: channel,
52	    accountId,
53	    patch,
54	    ensureChannelEnabled: false,
55	    ensureAccountEnabled: false,
56	  }) as CoreConfig;
57	}
58	
59	export function setIrcDmPolicy(cfg: CoreConfig, dmPolicy: DmPolicy): CoreConfig {
60	  return setIrcTopLevelDmPolicy(cfg, dmPolicy) as CoreConfig;
61	}
62	
63	export function setIrcAllowFrom(cfg: CoreConfig, allowFrom: string[]): CoreConfig {
64	  return setIrcTopLevelAllowFrom(cfg, allowFrom) as CoreConfig;
65	}
66	
67	export function setIrcNickServ(
68	  cfg: CoreConfig,
69	  accountId: string,
70	  nickserv?: IrcNickServConfig,
71	): CoreConfig {
72	  return updateIrcAccountConfig(cfg, accountId, { nickserv });
73	}
74	
75	export function setIrcGroupAccess(
76	  cfg: CoreConfig,
77	  accountId: string,
78	  policy: "open" | "allowlist" | "disabled",
79	  entries: string[],
80	  normalizeGroupEntry: (raw: string) => string | null,
81	): CoreConfig {
82	  if (policy !== "allowlist") {
83	    return updateIrcAccountConfig(cfg, accountId, { enabled: true, groupPolicy: policy });
84	  }
85	  const normalizedEntries = [
86	    ...new Set(entries.map((entry) => normalizeGroupEntry(entry)).filter(Boolean)),
87	  ];
88	  const groups = Object.fromEntries(normalizedEntries.map((entry) => [entry, {}]));
89	  return updateIrcAccountConfig(cfg, accountId, {
90	    enabled: true,
91	    groupPolicy: "allowlist",
92	    groups,
93	  });
94	}
95	
96	export const ircSetupAdapter: ChannelSetupAdapter = {
97	  resolveAccountId: ({ accountId }) => normalizeAccountId(accountId),
98	  applyAccountName: ({ cfg, accountId, name }) =>
99	    applyAccountNameToChannelSection({
100	      cfg,
101	      channelKey: channel,
102	      accountId,
103	      name,
104	    }),
105	  validateInput: createSetupInputPresenceValidator({
106	    whenNotUseEnv: [
107	      { someOf: ["host"], message: "IRC requires host." },
108	      { someOf: ["nick"], message: "IRC requires nick." },
109	    ],
110	  }),
111	  applyAccountConfig: ({ cfg, accountId, input }) => {
112	    const setupInput = input as IrcSetupInput;
113	    const namedConfig = applyAccountNameToChannelSection({
114	      cfg,
115	      channelKey: channel,
116	      accountId,
117	      name: setupInput.name,
118	    });
119	    const portInput =
120	      typeof setupInput.port === "number" ? String(setupInput.port) : String(setupInput.port ?? "");
121	    const patch: Partial<IrcAccountConfig> = {
122	      enabled: true,
123	      host: setupInput.host?.trim(),
