165	    const cleaned = line.replace(/[\r\n]+/g, "").trim();
166	    if (!cleaned) {
167	      throw new Error("IRC command cannot be empty");
168	    }
169	    socket.write(`${cleaned}\r\n`);
170	  };
171	
172	  const tryRecoverNickCollision = (): boolean => {
173	    const nickServEnabled = options.nickserv?.enabled !== false;
174	    const nickservPassword = sanitizeIrcOutboundText(options.nickserv?.password ?? "");
175	    if (nickServEnabled && !nickServRecoverAttempted && nickservPassword) {
176	      nickServRecoverAttempted = true;
177	      try {
178	        const service = sanitizeIrcTarget(options.nickserv?.service?.trim() || "NickServ");
179	        sendRaw(`PRIVMSG ${service} :GHOST ${desiredNick} ${nickservPassword}`);
180	        sendRaw(`NICK ${desiredNick}`);
181	        return true;
182	      } catch (err) {
183	        fail(err);
184	      }
185	    }
186	
187	    if (!fallbackNickAttempted) {
188	      fallbackNickAttempted = true;
189	      const fallbackNick = buildFallbackNick(desiredNick);
190	      if (fallbackNick.toLowerCase() !== currentNick.toLowerCase()) {
191	        try {
192	          sendRaw(`NICK ${fallbackNick}`);
193	          currentNick = fallbackNick;
194	          return true;
195	        } catch (err) {
196	          fail(err);
197	        }
198	      }
199	    }
200	    return false;
201	  };
202	
203	  const join = (channel: string) => {
204	    const target = sanitizeIrcTarget(channel);
