#### `extensions/pulseboard/src/normalize.ts`

Pure string normalization functions. No external SDK imports needed.

```typescript
const PULSEBOARD_TARGET_PATTERN = /^[^\s]+$/u;

/**
 * Returns true if the target is a board (group) target.
 * Boards are prefixed with '#'.
 */
export function isBoardTarget(target: string): boolean {
  return target.startsWith("#");
}

/**
 * Normalizes a raw PulseBoard messaging target string.
 * Strips `pulseboard:`, `board:`, and `user:` prefixes.
 * Adds `#` prefix for board: targets if not already present.
 * Returns undefined for empty or invalid targets.
 */
export function normalizePulseboardMessagingTarget(raw: string): string | undefined {
  const trimmed = raw.trim();
  if (!trimmed) return undefined;
  let target = trimmed;
  const lowered = target.toLowerCase();
  if (lowered.startsWith("pulseboard:")) {
    target = target.slice("pulseboard:".length).trim();
  }
  if (target.toLowerCase().startsWith("board:")) {
    target = target.slice("board:".length).trim();
    if (!target.startsWith("#")) {
      target = `#${target}`;
    }
  }
  if (target.toLowerCase().startsWith("user:")) {
    target = target.slice("user:".length).trim();
  }
  // Strip leading '@' from user targets (PulseBoard allows @username notation)
  if (!target.startsWith("#") && target.startsWith("@")) {
    target = target.slice(1).trim();
  }
  if (!target || !looksLikePulseboardTargetId(target)) {
    return undefined;
  }
  return target;
}

export function looksLikePulseboardTargetId(raw: string): boolean {
  const trimmed = raw.trim();
  if (!trimmed) return false;
  return PULSEBOARD_TARGET_PATTERN.test(trimmed);
}

/**
 * Normalizes an allow-from entry to lowercase username.
 * Strips `pulseboard:` and `user:` prefixes and `@` prefix.
 */
export function normalizePulseboardAllowEntry(raw: string): string {
  let value = raw.trim().toLowerCase();
  if (!value) return "";
  if (value.startsWith("pulseboard:")) value = value.slice("pulseboard:".length);
  if (value.startsWith("user:")) value = value.slice("user:".length);
  if (value.startsWith("@")) value = value.slice(1);
  return value.trim();
}

export function normalizePulseboardAllowlist(entries?: Array<string | number>): string[] {
  return (entries ?? []).map((e) => normalizePulseboardAllowEntry(String(e))).filter(Boolean);
}

/**
 * Formats a sender id string for display and allowlist matching.
 * PulseBoard uses simple usernames, so this is just the trimmed username.
 */
export function formatPulseboardSenderId(message: PulseboardInboundMessage): string {
  return message.senderUsername.trim();
}

/**
 * Builds candidate strings for allowlist matching from an inbound message.
 * PulseBoard uses only the username (no host/user mask).
 */
export function buildPulseboardAllowlistCandidates(message: PulseboardInboundMessage): string[] {
  const username = message.senderUsername.trim().toLowerCase();
  if (!username) return [];
  return [username];
}

/**
 * Resolves whether the message sender is in the allow list.
 */
export function resolvePulseboardAllowlistMatch(params: {
  allowFrom: string[];
  message: PulseboardInboundMessage;
}): { allowed: boolean; source?: string } {
  const allowFrom = new Set(params.allowFrom.map((e) => e.trim().toLowerCase()).filter(Boolean));
  if (allowFrom.has("*")) return { allowed: true, source: "wildcard" };
  const candidates = buildPulseboardAllowlistCandidates(params.message);
  for (const candidate of candidates) {
    if (allowFrom.has(candidate)) return { allowed: true, source: candidate };
  }
  return { allowed: false };
}
```

Note: `PulseboardInboundMessage` needs to be imported from `./types.js`.

