**`pulseboardSetupWizard: ChannelSetupWizard`:**
```typescript
export const pulseboardSetupWizard: ChannelSetupWizard = {
  channel,
  status: createStandardChannelSetupStatus({
    channelLabel: "PulseBoard",
    configuredLabel: "configured",
    unconfiguredLabel: "needs token + url",
    configuredHint: "configured",
    unconfiguredHint: "needs token + url",
    configuredScore: 1,
    unconfiguredScore: 0,
    includeStatusLine: true,
    resolveConfigured: ({ cfg }) =>
      listPulseboardAccountIds(cfg as CoreConfig).some(
        (accountId) => resolvePulseboardAccount({ cfg: cfg as CoreConfig, accountId }).configured,
      ),
  }),
  introNote: {
    title: "PulseBoard setup",
    lines: [
      "PulseBoard needs an API token and workspace URL.",
      "Env vars supported: PULSEBOARD_TOKEN, PULSEBOARD_URL.",
      'Set channels.pulseboard.groupPolicy="allowlist" and channels.pulseboard.boards for board control.',
      "Board targets use # prefix (e.g., #general). DM targets use username.",
      `Docs: ${formatDocsLink("/channels/pulseboard", "channels/pulseboard")}`,
    ],
    shouldShow: ({ cfg, accountId }) =>
      !resolvePulseboardAccount({ cfg: cfg as CoreConfig, accountId }).configured,
  },
  prepare: async ({ cfg, accountId, credentialValues, prompter }) => {
    const resolved = resolvePulseboardAccount({ cfg: cfg as CoreConfig, accountId });
    const isDefaultAccount = accountId === DEFAULT_ACCOUNT_ID;
    const envToken = isDefaultAccount ? process.env.PULSEBOARD_TOKEN?.trim() : "";
    const envUrl = isDefaultAccount ? process.env.PULSEBOARD_URL?.trim() : "";
    const envReady = Boolean(envToken && envUrl && !resolved.config.token && !resolved.config.url);
    if (envReady) {
      const useEnv = await prompter.confirm({
        message: "PULSEBOARD_TOKEN and PULSEBOARD_URL detected. Use env vars?",
        initialValue: true,
      });
      if (useEnv) {
        return {
          cfg: updatePulseboardAccountConfig(cfg as CoreConfig, accountId, { enabled: true }),
          credentialValues: { ...credentialValues, [USE_ENV_FLAG]: "1" },
        };
      }
    }
    return {
      cfg: updatePulseboardAccountConfig(cfg as CoreConfig, accountId, { enabled: true }),
      credentialValues: { ...credentialValues, [USE_ENV_FLAG]: "0" },
    };
  },
  credentials: [],
  textInputs: [
    {
      inputKey: "token",
      message: "PulseBoard API token",
      currentValue: ({ cfg, accountId }) =>
        resolvePulseboardAccount({ cfg: cfg as CoreConfig, accountId }).token || undefined,
      shouldPrompt: ({ credentialValues }) => credentialValues[USE_ENV_FLAG] !== "1",
      validate: ({ value }) => (String(value ?? "").trim() ? undefined : "Required"),
      normalizeValue: ({ value }) => String(value).trim(),
      applySet: async ({ cfg, accountId, value }) =>
        updatePulseboardAccountConfig(cfg as CoreConfig, accountId, { enabled: true, token: value }),
    },
    {
      inputKey: "userId",
      message: "PulseBoard workspace URL",
      placeholder: "https://myworkspace.pulseboard.example",
      currentValue: ({ cfg, accountId }) =>
        resolvePulseboardAccount({ cfg: cfg as CoreConfig, accountId }).url || undefined,
      shouldPrompt: ({ credentialValues }) => credentialValues[USE_ENV_FLAG] !== "1",
      validate: ({ value }) => {
        const v = String(value ?? "").trim();
        if (!v) return "Required";
        if (!v.startsWith("http://") && !v.startsWith("https://")) return "Must be a valid URL";
        return undefined;
      },
      normalizeValue: ({ value }) => String(value).trim().replace(/\/$/, ""),
      applySet: async ({ cfg, accountId, value }) =>
        updatePulseboardAccountConfig(cfg as CoreConfig, accountId, { enabled: true, url: value }),
    },
    {
      inputKey: "groupChannels",
      message: "Subscribe to boards (optional, comma-separated)",
      placeholder: "#general, #ops",
      required: false,
      applyEmptyValue: true,
      currentValue: ({ cfg, accountId }) =>
        resolvePulseboardAccount({ cfg: cfg as CoreConfig, accountId }).config.subscribedBoards?.join(", "),
      shouldPrompt: ({ credentialValues }) => credentialValues[USE_ENV_FLAG] !== "1",
      normalizeValue: ({ value }) =>
        parseListInput(String(value))
          .map((e) => normalizeBoardEntry(e))
          .filter((e): e is string => Boolean(e && e !== "*"))
          .filter((e) => isBoardTarget(e))
          .join(", "),
      applySet: async ({ cfg, accountId, value }) => {
        const boards = parseListInput(String(value))
          .map((e) => normalizeBoardEntry(e))
          .filter((e): e is string => Boolean(e && e !== "*"))
          .filter((e) => isBoardTarget(e));
        return updatePulseboardAccountConfig(cfg as CoreConfig, accountId, {
          enabled: true,
          subscribedBoards: boards.length > 0 ? boards : undefined,
        });
      },
    },
  ],
  groupAccess: {
    label: "PulseBoard boards",
    placeholder: "#general, #ops, *",
    currentPolicy: ({ cfg, accountId }) =>
      resolvePulseboardAccount({ cfg: cfg as CoreConfig, accountId }).config.groupPolicy ?? "allowlist",
    currentEntries: ({ cfg, accountId }) =>
      Object.keys(resolvePulseboardAccount({ cfg: cfg as CoreConfig, accountId }).config.boards ?? {}),
    updatePrompt: ({ cfg, accountId }) =>
      Boolean(resolvePulseboardAccount({ cfg: cfg as CoreConfig, accountId }).config.boards),
    setPolicy: ({ cfg, accountId, policy }) =>
      setPulseboardGroupAccess(cfg as CoreConfig, accountId, policy, [], normalizeBoardEntry),
    resolveAllowlist: async ({ entries }) =>
      [...new Set(entries.map((e) => normalizeBoardEntry(e)).filter(Boolean))] as string[],
    applyAllowlist: ({ cfg, accountId, resolved }) =>
      setPulseboardGroupAccess(cfg as CoreConfig, accountId, "allowlist", resolved as string[], normalizeBoardEntry),
  },
  allowFrom: createAllowFromSection({
    helpTitle: "PulseBoard allowlist",
    helpLines: [
      "Allowlist PulseBoard DMs by username.",
      "Examples: alice, bob",
      "Multiple entries: comma-separated.",
    ],
    message: "PulseBoard allowFrom (username)",
    placeholder: "alice, bob",
    invalidWithoutCredentialNote: "Use a PulseBoard username.",
    parseId: (raw) => normalizePulseboardAllowEntry(raw) || null,
    apply: async ({ cfg, allowFrom }) => setPulseboardAllowFrom(cfg as CoreConfig, allowFrom),
  }),
  finalize: async ({ cfg, accountId, prompter }) => {
    let next = cfg as CoreConfig;
    const resolvedAfterGroups = resolvePulseboardAccount({ cfg: next, accountId });
    if (resolvedAfterGroups.config.groupPolicy === "allowlist") {
      const boardKeys = Object.keys(resolvedAfterGroups.config.boards ?? {});
      if (boardKeys.length > 0) {
        const wantsMentions = await prompter.confirm({
          message: "Require @mention to reply in PulseBoard boards?",
          initialValue: true,
        });
        if (!wantsMentions) {
          const boards = resolvedAfterGroups.config.boards ?? {};
          const patched = Object.fromEntries(
            Object.entries(boards).map(([key, value]) => [key, { ...value, requireMention: false }]),
          );
          next = updatePulseboardAccountConfig(next, accountId, { boards: patched });
        }
      }
    }
    return { cfg: next };
  },
  completionNote: {
    title: "PulseBoard next steps",
    lines: [
      "Next: restart gateway and verify status.",
      "Command: openclaw channels status --probe",
      `Docs: ${formatDocsLink("/channels/pulseboard", "channels/pulseboard")}`,
    ],
  },
  dmPolicy: pulseboardDmPolicy,
  disable: (cfg) => setSetupChannelEnabled(cfg, channel, false),
};

export { pulseboardSetupAdapter };
```

