import { afterEach, describe, expect, it } from "vitest";
import { pulseboardPlugin } from "./channel.js";
import { clearPulseboardRuntime } from "./runtime.js";

describe("pulseboard outbound chunking", () => {
  afterEach(() => {
    clearPulseboardRuntime();
  });

  it("chunks outbound text without requiring PulseBoard runtime initialization", () => {
    const chunker = pulseboardPlugin.outbound?.chunker;
    if (!chunker) {
      throw new Error("pulseboard outbound.chunker unavailable");
    }
    // PulseBoard has a 4000-char limit; verify short text passes through
    expect(chunker("hello world", 4000)).toEqual(["hello world"]);
    // Verify chunking splits on word boundaries within limit
    expect(chunker("alpha beta", 5)).toEqual(["alpha", "beta"]);
  });
});
```

---

### Implementation Sequencing

Implement files in this dependency order to avoid forward-reference issues:

1. `package.json`, `openclaw.plugin.json` — metadata, no code deps
2. `src/types.ts` — pure type definitions, only imports from `./runtime-api.js`
3. `src/runtime-api.ts` — re-export barrel from SDK subpaths (no local deps)
4. `src/runtime.ts` — depends on `runtime-api.ts`
5. `src/config-ui-hints.ts` — pure data, depends on SDK type only
6. `src/config-schema.ts` — depends on `config-ui-hints.ts`
7. `src/normalize.ts` — pure functions, depends on `types.ts`
8. `src/policy.ts` — depends on `normalize.ts`, `types.ts`
9. `src/accounts.ts` — depends on `types.ts`
10. `src/client.ts` — pure network stub, no local deps
11. `src/probe.ts` — depends on `accounts.ts`, `client.ts`, `types.ts`
12. `src/send.ts` — depends on `accounts.ts`, `client.ts`, `normalize.ts`, `runtime.ts`, `types.ts`
13. `src/inbound.ts` — depends on `accounts.ts`, `normalize.ts`, `policy.ts`, `runtime-api.ts`, `runtime.ts`, `send.ts`, `types.ts`
14. `src/monitor.ts` — depends on `accounts.ts`, `client.ts`, `inbound.ts`, `normalize.ts`, `runtime-api.ts`, `runtime.ts`, `types.ts`
15. `src/setup-core.ts` — depends on `types.ts`
16. `src/setup-surface.ts` — depends on `accounts.ts`, `normalize.ts`, `setup-core.ts`, `types.ts`
17. `src/channel.ts` — depends on everything
18. `src/channel.test.ts` — depends on `channel.ts`, `runtime.ts`
19. `channel-config-api.ts` — depends on `src/config-schema.ts`
20. `api.ts` — depends on `src/accounts.ts`, `src/setup-surface.ts`
21. `setup-entry.ts` — depends on `src/channel.ts`
22. `index.ts` — depends on `src/channel.ts`, `src/runtime.ts`

---

### Key Design Decisions and Differences from IRC

1. **Credential model**: Two fields (`token` + `url`) instead of IRC's many connection fields (`host`, `port`, `tls`, `nick`, `username`, `realname`, `password`). The `configured` check is `Boolean(token && url)`.

2. **Identity model**: PulseBoard uses plain usernames. There is no `nick!user@host` mask. `buildPulseboardAllowlistCandidates` returns only the username. `resolvePulseboardAllowlistMatch` only checks the username string. This simplifies allowlist matching significantly compared to IRC.

3. **Group naming**: `boards` replaces `groups` everywhere. `subscribedBoards` replaces `channels`. `#board-name` is the canonical form for group targets.

4. **`groupAllowFromFallbackToAllowFrom`**: Set to `true` in `resolvePulseboardEffectiveAllowlists` (unlike IRC which uses `false`). PulseBoard's simpler identity model makes the fallback safe.

5. **Client stub**: Uses HTTP polling simulation instead of a real WebSocket, avoiding any new `package.json` dependencies. The API surface matches what the rest of the plugin expects.

6. **`textChunkLimit: 4000`**: Per the requirements. IRC uses 350.

7. **No `dangerouslyAllowNameMatching`**: IRC has a break-glass override for nick-only matching because its full-identity default (`nick!user@host`) can be surprising. PulseBoard uses only usernames, so there is no equivalent concept.

8. **`runtime-api.ts` imports**: Since there is no `openclaw/plugin-sdk/pulseboard`, each symbol is imported directly from its specific SDK subpath. The IRC plugin had the luxury of a single `openclaw/plugin-sdk/irc` facade that re-exported everything. PulseBoard must enumerate sources per-symbol.

9. **`From` field format in inbound context**: Uses `pulseboard:board:${target}` for groups (to clearly distinguish from DM targets) vs IRC's `irc:channel:${target}`.

---

### Potential Pitfalls

- The exact SDK subpath for each import in `runtime-api.ts` must be verified against the plugin-sdk build at implementation time. The `plugin-sdk-entrypoints.json` file lists all valid subpaths; use that as the reference.
- `composeWarningCollectors` vs `composeAccountWarningCollectors`: The channel.ts IRC file uses both; PulseBoard's simpler warning set may only need `composeAccountWarningCollectors`. Verify which compose helper matches the intended call signature.
- The `client.ts` HTTP polling stub must handle the case where the abort signal fires mid-poll. Clear the interval in the abort handler.
- `normalizeBoardEntry` in `setup-surface.ts` must not strip the `#` from board names that already have it, and must add `#` to names that lack it (unless the entry is `*`).

