// Simulates a connection by returning a stub client after a brief delay.
// In a real implementation this would open a WebSocket.
// The stub: generates a userId from the token hash, resolves after
// connectTimeoutMs (default 5000ms), throws if abortSignal is aborted.
// sendMessage: records outbound, calls onMessage stub; returns a fake messageId.
export async function connectPulseBoardClient(
  opts: PulseBoardClientOptions,
): Promise<PulseBoardClient>
