import { afterEach, describe, expect, it } from "vitest";
import { pulseBoardPlugin } from "./channel.js";
import { clearPulseBoardRuntime } from "./runtime.js";

describe("pulseboard outbound chunking", () => {
  afterEach(() => {
    clearPulseBoardRuntime();
  });

  it("chunks outbound text without requiring PulseBoard runtime initialization", () => {
    const chunker = pulseBoardPlugin.outbound?.chunker;
    if (!chunker) throw new Error("pulseboard outbound.chunker unavailable");
    // textChunkLimit is 4000; chunker should split at word boundary
    expect(chunker("hello world", 5)).toEqual(["hello", "world"]);
  });

  it("respects 4000-character chunk limit declared in plugin", () => {
    const limit = 4000;
    const text = "x".repeat(limit + 100);
    const chunker = pulseBoardPlugin.outbound?.chunker;
    if (!chunker) throw new Error("pulseboard outbound.chunker unavailable");
    const chunks = chunker(text, limit);
    expect(chunks.length).toBeGreaterThan(1);
    for (const chunk of chunks) {
      expect(chunk.length).toBeLessThanOrEqual(limit);
    }
  });
});
