### 12. `extensions/pulseboard/src/client.ts`

Fictional PulseBoard WebSocket client stub. Since PulseBoard is imaginary, this provides a realistic interface without a real protocol implementation.

```typescript
export type PulseBoardClientOptions = {
  token: string;
  url: string;
  connectTimeoutMs?: number;
  abortSignal?: AbortSignal;
  onMessage?: (event: PulseBoardMessageEvent) => void | Promise<void>;
  onError?: (error: Error) => void;
  onDisconnect?: () => void;
};

export type PulseBoardMessageEvent = {
  messageId: string;
  boardId?: string;        // set for board messages
  senderId: string;        // user id
  senderName?: string;
  text: string;
  isGroup: boolean;
  timestamp: number;
};

export type PulseBoardClient = {
  readonly userId: string;
  readonly url: string;
  isReady(): boolean;
  sendMessage(target: string, text: string): Promise<{ messageId: string }>;
  disconnect(): void;
};

// connectPulseBoardClient(options): Promise<PulseBoardClient>
// Simulates a connection by returning a stub client after a brief delay.
// In a real implementation this would open a WebSocket.
// The stub: generates a userId from the token hash, resolves after
// connectTimeoutMs (default 5000ms), throws if abortSignal is aborted.
// sendMessage: records outbound, calls onMessage stub; returns a fake messageId.
export async function connectPulseBoardClient(
  opts: PulseBoardClientOptions,
): Promise<PulseBoardClient>
```

