187	    if (!fallbackNickAttempted) {
188	      fallbackNickAttempted = true;
189	      const fallbackNick = buildFallbackNick(desiredNick);
190	      if (fallbackNick.toLowerCase() !== currentNick.toLowerCase()) {
191	        try {
192	          sendRaw(`NICK ${fallbackNick}`);
193	          currentNick = fallbackNick;
194	          return true;
195	        } catch (err) {
196	          fail(err);
197	        }
198	      }
199	    }
200	    return false;
201	  };
202	
203	  const join = (channel: string) => {
204	    const target = sanitizeIrcTarget(channel);
205	    if (!target.startsWith("#") && !target.startsWith("&")) {
206	      throw new Error(`IRC JOIN target must be a channel: ${channel}`);
207	    }
208	    sendRaw(`JOIN ${target}`);
209	  };
210	
211	  const sendPrivmsg = (target: string, text: string) => {
212	    const normalizedTarget = sanitizeIrcTarget(target);
213	    const cleaned = sanitizeIrcOutboundText(text);
214	    if (!cleaned) {
215	      return;
216	    }
217	    let remaining = cleaned;
218	    while (remaining.length > 0) {
219	      let chunk = remaining;
220	      if (chunk.length > messageChunkMaxChars) {
221	        let splitAt = chunk.lastIndexOf(" ", messageChunkMaxChars);
222	        if (splitAt < Math.floor(messageChunkMaxChars / 2)) {
223	          splitAt = messageChunkMaxChars;
224	        }
225	        chunk = chunk.slice(0, splitAt).trim();
226	      }
227	      if (!chunk) {
228	        break;
229	      }
230	      sendRaw(`PRIVMSG ${normalizedTarget} :${chunk}`);
231	      remaining = remaining.slice(chunk.length).trimStart();
232	    }
233	  };
234	
235	  const quit = (reason?: string) => {
236	    if (closed) {
237	      return;
238	    }
239	    closed = true;
240	    const safeReason = sanitizeIrcOutboundText(reason != null ? reason : "bye");
241	    try {
242	      if (safeReason) {
243	        sendRaw(`QUIT :${safeReason}`);
244	      } else {
245	        sendRaw("QUIT");
246	      }
247	    } catch {
248	      // Ignore quit failures while shutting down.
249	    }
250	    socket.end();
251	  };
252	
253	  const close = () => {
254	    if (closed) {
255	      return;
256	    }
257	    closed = true;
258	    socket.destroy();
259	  };
260	
261	  let buffer = "";
262	  socket.on("data", (chunk: string) => {
263	    buffer += chunk;
264	    let idx = buffer.indexOf("\n");
265	    while (idx !== -1) {
266	      const rawLine = buffer.slice(0, idx).replace(/\r$/, "");
267	      buffer = buffer.slice(idx + 1);
268	      idx = buffer.indexOf("\n");
269	
270	      if (!rawLine) {
271	        continue;
272	      }
273	      if (options.onLine) {
274	        options.onLine(rawLine);
275	      }
276	
277	      const line = parseIrcLine(rawLine);
278	      if (!line) {
279	        continue;
280	      }
281	
282	      if (line.command === "PING") {
283	        const payload =
284	          line.trailing != null ? line.trailing : line.params[0] != null ? line.params[0] : "";
285	        sendRaw(`PONG :${payload}`);
286	        continue;
287	      }
288	
289	      if (line.command === "NICK") {
290	        const prefix = parseIrcPrefix(line.prefix);
291	        if (prefix.nick && prefix.nick.toLowerCase() === currentNick.toLowerCase()) {
292	          const next =
293	            line.trailing != null
294	              ? line.trailing
295	              : line.params[0] != null
296	                ? line.params[0]
297	                : currentNick;
298	          currentNick = String(next).trim();
299	        }
300	        continue;
301	      }
302	
303	      if (!ready && IRC_NICK_COLLISION_CODES.has(line.command)) {
304	        if (tryRecoverNickCollision()) {
305	          continue;
306	        }
307	        const detail =
308	          line.trailing != null ? line.trailing : line.params.join(" ") || "nickname in use";
309	        fail(new Error(`IRC login failed (${line.command}): ${detail}`));
310	        close();
311	        return;
312	      }
313	
314	      if (!ready && IRC_ERROR_CODES.has(line.command)) {
315	        const detail =
316	          line.trailing != null ? line.trailing : line.params.join(" ") || "login rejected";
317	        fail(new Error(`IRC login failed (${line.command}): ${detail}`));
318	        close();
319	        return;
320	      }
321	
322	      if (line.command === "001") {
323	        ready = true;
324	        const nickParam = line.params[0];
325	        if (nickParam && nickParam.trim()) {
326	          currentNick = nickParam.trim();
327	        }
328	        try {
329	          const nickServCommands = buildIrcNickServCommands(options.nickserv);
330	          for (const command of nickServCommands) {
331	            sendRaw(command);
332	          }
333	        } catch (err) {
334	          fail(err);
335	        }
336	        for (const channel of options.channels || []) {
337	          const trimmed = channel.trim();
338	          if (!trimmed) {
339	            continue;
340	          }
341	          try {
342	            join(trimmed);
343	          } catch (err) {
344	            fail(err);
345	          }
346	        }
347	        if (resolveReady) {
348	          resolveReady();
349	        }
350	        resolveReady = null;
351	        rejectReady = null;
352	        continue;
353	      }
354	
355	      if (line.command === "NOTICE") {
356	        if (options.onNotice) {
357	          options.onNotice(line.trailing != null ? line.trailing : "", line.params[0]);
358	        }
359	        continue;
360	      }
361	
362	      if (line.command === "PRIVMSG") {
363	        const targetParam = line.params[0];
364	        const target = targetParam ? targetParam.trim() : "";
365	        const text = line.trailing != null ? line.trailing : "";
366	        const prefix = parseIrcPrefix(line.prefix);
367	        const senderNick = prefix.nick ? prefix.nick.trim() : "";
368	        if (!target || !senderNick || !text.trim()) {
369	          continue;
370	        }
371	        if (options.onPrivmsg) {
372	          void Promise.resolve(
373	            options.onPrivmsg({
374	              senderNick,
375	              senderUser: prefix.user ? prefix.user.trim() : undefined,
376	              senderHost: prefix.host ? prefix.host.trim() : undefined,
377	              target,
378	              text,
379	              rawLine,
380	            }),
381	          ).catch((error) => {
382	            fail(error);
383	          });
384	        }
385	      }
386	    }
387	  });
388	
389	  socket.once("connect", () => {
390	    try {
391	      if (options.password && options.password.trim()) {
392	        sendRaw(`PASS ${options.password.trim()}`);
393	      }
394	      sendRaw(`NICK ${options.nick.trim()}`);
395	      sendRaw(`USER ${options.username.trim()} 0 * :${sanitizeIrcOutboundText(options.realname)}`);
396	    } catch (err) {
397	      fail(err);
398	      close();
399	    }
400	  });
401	
402	  socket.once("error", (err: unknown) => {
403	    fail(err);
404	  });
405	
406	  socket.once("close", () => {
407	    if (!closed) {
408	      closed = true;
409	      if (!ready) {
410	        fail(new Error("IRC connection closed before ready"));
411	      }
412	    }
413	  });
414	
415	  if (options.abortSignal) {
416	    const abort = () => {
417	      quit("shutdown");
418	    };
419	    if (options.abortSignal.aborted) {
420	      abort();
421	    } else {
422	      options.abortSignal.addEventListener("abort", abort, { once: true });
423	    }
424	  }
425	
426	  await withTimeout(readyPromise, timeoutMs, "IRC connect");
427	
428	  return {
429	    get nick() {
430	      return currentNick;
431	    },
432	    isReady: () => ready && !closed,
433	    sendRaw,
434	    join,
435	    sendPrivmsg,
436	    quit,
437	    close,
438	  };
439	}
