81	export async function handleIrcInbound(params: {
82	  message: IrcInboundMessage;
83	  account: ResolvedIrcAccount;
84	  config: CoreConfig;
85	  runtime: RuntimeEnv;
86	  connectedNick?: string;
87	  sendReply?: (target: string, text: string, replyToId?: string) => Promise<void>;
88	  statusSink?: (patch: { lastInboundAt?: number; lastOutboundAt?: number }) => void;
89	}): Promise<void> {
90	  const { message, account, config, runtime, connectedNick, statusSink } = params;
91	  const core = getIrcRuntime();
92	  const pairing = createChannelPairingController({
93	    core,
94	    channel: CHANNEL_ID,
95	    accountId: account.accountId,
96	  });
97	
98	  const rawBody = message.text?.trim() ?? "";
99	  if (!rawBody) {
100	    return;
101	  }
102	
103	  statusSink?.({ lastInboundAt: message.timestamp });
104	
105	  const senderDisplay = message.senderHost
106	    ? `${message.senderNick}!${message.senderUser ?? "?"}@${message.senderHost}`
107	    : message.senderNick;
108	  const allowNameMatching = isDangerousNameMatchingEnabled(account.config);
109	
110	  const dmPolicy = account.config.dmPolicy ?? "pairing";
111	  const defaultGroupPolicy = resolveDefaultGroupPolicy(config);
112	  const { groupPolicy, providerMissingFallbackApplied } =
113	    resolveAllowlistProviderRuntimeGroupPolicy({
114	      providerConfigPresent: config.channels?.irc !== undefined,
115	      groupPolicy: account.config.groupPolicy,
116	      defaultGroupPolicy,
117	    });
118	  warnMissingProviderGroupPolicyFallbackOnce({
119	    providerMissingFallbackApplied,
120	    providerKey: "irc",
121	    accountId: account.accountId,
122	    blockedLabel: GROUP_POLICY_BLOCKED_LABEL.channel,
123	    log: (message) => runtime.log?.(message),
124	  });
125	
126	  const configAllowFrom = normalizeIrcAllowlist(account.config.allowFrom);
127	  const configGroupAllowFrom = normalizeIrcAllowlist(account.config.groupAllowFrom);
128	  const storeAllowFrom = await readStoreAllowFromForDmPolicy({
129	    provider: CHANNEL_ID,
130	    accountId: account.accountId,
131	    dmPolicy,
132	    readStore: pairing.readStoreForDmPolicy,
133	  });
134	  const storeAllowList = normalizeIrcAllowlist(storeAllowFrom);
135	
136	  const groupMatch = resolveIrcGroupMatch({
137	    groups: account.config.groups,
138	    target: message.target,
139	  });
140	
141	  if (message.isGroup) {
142	    const groupAccess = resolveIrcGroupAccessGate({ groupPolicy, groupMatch });
143	    if (!groupAccess.allowed) {
144	      runtime.log?.(`irc: drop channel ${message.target} (${groupAccess.reason})`);
145	      return;
146	    }
147	  }
148	
149	  const directGroupAllowFrom = normalizeIrcAllowlist(groupMatch.groupConfig?.allowFrom);
150	  const wildcardGroupAllowFrom = normalizeIrcAllowlist(groupMatch.wildcardConfig?.allowFrom);
151	  const groupAllowFrom =
152	    directGroupAllowFrom.length > 0 ? directGroupAllowFrom : wildcardGroupAllowFrom;
153	
154	  const { effectiveAllowFrom, effectiveGroupAllowFrom } = resolveIrcEffectiveAllowlists({
155	    configAllowFrom,
156	    configGroupAllowFrom,
157	    storeAllowList,
158	    dmPolicy,
159	  });
160	
161	  const allowTextCommands = core.channel.commands.shouldHandleTextCommands({
162	    cfg: config as OpenClawConfig,
163	    surface: CHANNEL_ID,
164	  });
165	  const useAccessGroups = config.commands?.useAccessGroups !== false;
166	  const senderAllowedForCommands = resolveIrcAllowlistMatch({
167	    allowFrom: message.isGroup ? effectiveGroupAllowFrom : effectiveAllowFrom,
168	    message,
169	    allowNameMatching,
170	  }).allowed;
171	  const hasControlCommand = core.channel.text.hasControlCommand(rawBody, config as OpenClawConfig);
172	  const commandGate = resolveControlCommandGate({
173	    useAccessGroups,
174	    authorizers: [
175	      {
176	        configured: (message.isGroup ? effectiveGroupAllowFrom : effectiveAllowFrom).length > 0,
177	        allowed: senderAllowedForCommands,
178	      },
179	    ],
180	    allowTextCommands,
181	    hasControlCommand,
182	  });
183	  const commandAuthorized = commandGate.commandAuthorized;
184	
185	  if (message.isGroup) {
186	    const senderAllowed = resolveIrcGroupSenderAllowed({
187	      groupPolicy,
188	      message,
189	      outerAllowFrom: effectiveGroupAllowFrom,
190	      innerAllowFrom: groupAllowFrom,
191	      allowNameMatching,
192	    });
193	    if (!senderAllowed) {
194	      runtime.log?.(`irc: drop group sender ${senderDisplay} (policy=${groupPolicy})`);
195	      return;
196	    }
197	  } else {
198	    if (dmPolicy === "disabled") {
199	      runtime.log?.(`irc: drop DM sender=${senderDisplay} (dmPolicy=disabled)`);
200	      return;
201	    }
202	    if (dmPolicy !== "open") {
203	      const dmAllowed = resolveIrcAllowlistMatch({
204	        allowFrom: effectiveAllowFrom,
205	        message,
206	        allowNameMatching,
207	      }).allowed;
208	      if (!dmAllowed) {
209	        if (dmPolicy === "pairing") {
210	          await pairing.issueChallenge({
211	            senderId: senderDisplay.toLowerCase(),
212	            senderIdLine: `Your IRC id: ${senderDisplay}`,
213	            meta: { name: message.senderNick || undefined },
214	            sendPairingReply: async (text) => {
215	              await deliverIrcReply({
216	                payload: { text },
217	                target: message.senderNick,
218	                accountId: account.accountId,
219	                sendReply: params.sendReply,
220	                statusSink,
221	              });
222	            },
223	            onReplyError: (err) => {
224	              runtime.error?.(`irc: pairing reply failed for ${senderDisplay}: ${String(err)}`);
225	            },
226	          });
227	        }
228	        runtime.log?.(`irc: drop DM sender ${senderDisplay} (dmPolicy=${dmPolicy})`);
229	        return;
230	      }
231	    }
232	  }
233	
234	  if (message.isGroup && commandGate.shouldBlock) {
235	    logInboundDrop({
236	      log: (line) => runtime.log?.(line),
237	      channel: CHANNEL_ID,
238	      reason: "control command (unauthorized)",
239	      target: senderDisplay,
240	    });
241	    return;
242	  }
243	
244	  const mentionRegexes = core.channel.mentions.buildMentionRegexes(config as OpenClawConfig);
245	  const mentionNick = connectedNick?.trim() || account.nick;
246	  const explicitMentionRegex = mentionNick
247	    ? new RegExp(`\\b${escapeIrcRegexLiteral(mentionNick)}\\b[:,]?`, "i")
248	    : null;
249	  const wasMentioned =
250	    core.channel.mentions.matchesMentionPatterns(rawBody, mentionRegexes) ||
251	    (explicitMentionRegex ? explicitMentionRegex.test(rawBody) : false);
252	
253	  const requireMention = message.isGroup
254	    ? resolveIrcRequireMention({
255	        groupConfig: groupMatch.groupConfig,
256	        wildcardConfig: groupMatch.wildcardConfig,
257	      })
258	    : false;
259	
260	  const mentionGate = resolveIrcMentionGate({
261	    isGroup: message.isGroup,
262	    requireMention,
263	    wasMentioned,
264	    hasControlCommand,
265	    allowTextCommands,
266	    commandAuthorized,
267	  });
268	  if (mentionGate.shouldSkip) {
269	    runtime.log?.(`irc: drop channel ${message.target} (${mentionGate.reason})`);
270	    return;
271	  }
272	
273	  const peerId = message.isGroup ? message.target : message.senderNick;
274	  const route = core.channel.routing.resolveAgentRoute({
275	    cfg: config as OpenClawConfig,
276	    channel: CHANNEL_ID,
277	    accountId: account.accountId,
278	    peer: {
279	      kind: message.isGroup ? "group" : "direct",
280	      id: peerId,
281	    },
282	  });
283	
284	  const fromLabel = message.isGroup ? message.target : senderDisplay;
285	  const storePath = core.channel.session.resolveStorePath(config.session?.store, {
286	    agentId: route.agentId,
287	  });
288	  const envelopeOptions = core.channel.reply.resolveEnvelopeFormatOptions(config as OpenClawConfig);
289	  const previousTimestamp = core.channel.session.readSessionUpdatedAt({
290	    storePath,
291	    sessionKey: route.sessionKey,
292	  });
293	  const body = core.channel.reply.formatAgentEnvelope({
294	    channel: "IRC",
295	    from: fromLabel,
296	    timestamp: message.timestamp,
297	    previousTimestamp,
298	    envelope: envelopeOptions,
299	    body: rawBody,
300	  });
301	
302	  const groupSystemPrompt = groupMatch.groupConfig?.systemPrompt?.trim() || undefined;
303	
304	  const ctxPayload = core.channel.reply.finalizeInboundContext({
305	    Body: body,
306	    RawBody: rawBody,
307	    CommandBody: rawBody,
308	    From: message.isGroup ? `irc:channel:${message.target}` : `irc:${senderDisplay}`,
309	    To: `irc:${peerId}`,
310	    SessionKey: route.sessionKey,
311	    AccountId: route.accountId,
312	    ChatType: message.isGroup ? "group" : "direct",
313	    ConversationLabel: fromLabel,
314	    SenderName: message.senderNick || undefined,
315	    SenderId: senderDisplay,
316	    GroupSubject: message.isGroup ? message.target : undefined,
317	    GroupSystemPrompt: message.isGroup ? groupSystemPrompt : undefined,
318	    Provider: CHANNEL_ID,
319	    Surface: CHANNEL_ID,
320	    WasMentioned: message.isGroup ? wasMentioned : undefined,
321	    MessageSid: message.messageId,
322	    Timestamp: message.timestamp,
323	    OriginatingChannel: CHANNEL_ID,
324	    OriginatingTo: `irc:${peerId}`,
325	    CommandAuthorized: commandAuthorized,
326	  });
327	
328	  await dispatchInboundReplyWithBase({
329	    cfg: config as OpenClawConfig,
330	    channel: CHANNEL_ID,
331	    accountId: account.accountId,
332	    route,
333	    storePath,
334	    ctxPayload,
335	    core,
336	    deliver: async (payload) => {
337	      await deliverIrcReply({
338	        payload,
339	        target: peerId,
340	        accountId: account.accountId,
341	        sendReply: params.sendReply,
342	        statusSink,
343	      });
344	    },
345	    onRecordError: (err) => {
346	      runtime.error?.(`irc: failed updating session meta: ${String(err)}`);
347	    },
348	    onDispatchError: (err, info) => {
349	      runtime.error?.(`irc ${info.kind} reply failed: ${String(err)}`);
350	    },
351	    replyOptions: {
352	      skillFilter: groupMatch.groupConfig?.skills,
353	      disableBlockStreaming:
354	        typeof account.config.blockStreaming === "boolean"
355	          ? !account.config.blockStreaming
356	          : undefined,
357	    },
358	  });
359	}
