44	export function updateIrcAccountConfig(
45	  cfg: CoreConfig,
46	  accountId: string,
47	  patch: Partial<IrcAccountConfig>,
48	): CoreConfig {
49	  return patchScopedAccountConfig({
50	    cfg,
51	    channelKey: channel,
52	    accountId,
53	    patch,
54	    ensureChannelEnabled: false,
55	    ensureAccountEnabled: false,
56	  }) as CoreConfig;
57	}
