64	  return setIrcTopLevelAllowFrom(cfg, allowFrom) as CoreConfig;
65	}
66	
67	export function setIrcNickServ(
68	  cfg: CoreConfig,
69	  accountId: string,
70	  nickserv?: IrcNickServConfig,
71	): CoreConfig {
72	  return updateIrcAccountConfig(cfg, accountId, { nickserv });
73	}
74	
75	export function setIrcGroupAccess(
76	  cfg: CoreConfig,
77	  accountId: string,
78	  policy: "open" | "allowlist" | "disabled",
79	  entries: string[],
80	  normalizeGroupEntry: (raw: string) => string | null,
81	): CoreConfig {
82	  if (policy !== "allowlist") {
83	    return updateIrcAccountConfig(cfg, accountId, { enabled: true, groupPolicy: policy });
84	  }
85	  const normalizedEntries = [
86	    ...new Set(entries.map((entry) => normalizeGroupEntry(entry)).filter(Boolean)),
87	  ];
88	  const groups = Object.fromEntries(normalizedEntries.map((entry) => [entry, {}]));
89	  return updateIrcAccountConfig(cfg, accountId, {
90	    enabled: true,
91	    groupPolicy: "allowlist",
92	    groups,
93	  });
94	}
