116	      accountId,
117	      name: setupInput.name,
118	    });
119	    const portInput =
120	      typeof setupInput.port === "number" ? String(setupInput.port) : String(setupInput.port ?? "");
121	    const patch: Partial<IrcAccountConfig> = {
122	      enabled: true,
123	      host: setupInput.host?.trim(),
124	      port: portInput ? parsePort(portInput, setupInput.tls === false ? 6667 : 6697) : undefined,
125	      tls: setupInput.tls,
126	      nick: setupInput.nick?.trim(),
127	      username: setupInput.username?.trim(),
128	      realname: setupInput.realname?.trim(),
129	      password: setupInput.password?.trim(),
130	      channels: setupInput.channels,
