import { randomUUID } from "node:crypto";

/**
 * Stub PulseBoard client.
 *
 * PulseBoard is a fictional platform, so this client simulates a connection
 * via an in-process event emitter rather than a real network socket. It
 * exposes the same async lifecycle contract as real channel clients so that
 * monitor.ts and send.ts can remain structurally identical to the IRC plugin.
 */

export type PulseBoardMessageEvent = {
  messageId: string;
  senderUsername: string;
  target: string;
  text: string;
  isGroup: boolean;
};

export type PulseBoardClientOptions = {
  url: string;
  token: string;
  username: string;
  boards?: string[];
  connectTimeoutMs?: number;
  abortSignal?: AbortSignal;
  onMessage?: (event: PulseBoardMessageEvent) => void | Promise<void>;
  onError?: (error: Error) => void;
};

export type PulseBoardClient = {
  username: string;
  isReady: () => boolean;
  sendToBoard: (board: string, text: string) => void;
  sendDm: (recipientUsername: string, text: string) => void;
  disconnect: () => void;
};

function toError(err: unknown): Error {
  if (err instanceof Error) {
    return err;
  }
  return new Error(typeof err === "string" ? err : JSON.stringify(err));
}

export function makePulseBoardMessageId(): string {
  return randomUUID();
}

/**
 * Connect to the PulseBoard server.
 *
 * The stub validates that `url`, `token`, and `username` are non-empty and
 * resolves after a simulated handshake delay, returning a client handle.
 */
export async function connectPulseBoardClient(
  options: PulseBoardClientOptions,
): Promise<PulseBoardClient> {
  const timeoutMs = options.connectTimeoutMs ?? 10000;

  if (!options.url.trim()) {
    throw new Error("PulseBoard URL is required");
  }
  if (!options.token.trim()) {
    throw new Error("PulseBoard token is required");
  }
  if (!options.username.trim()) {
    throw new Error("PulseBoard username is required");
  }

  let ready = false;
  let closed = false;

  // Simulate an async authentication handshake with a short delay.
  await new Promise<void>((resolve, reject) => {
    const timer = setTimeout(() => {
      reject(new Error(`PulseBoard connect timed out after ${timeoutMs}ms`));
    }, timeoutMs);

    // Simulate fast async resolution (no real network in the stub).
    setImmediate(() => {
      clearTimeout(timer);
      if (options.abortSignal?.aborted) {
        reject(new Error("PulseBoard connect aborted"));
        return;
      }
      ready = true;
      resolve();
    });
  });

  if (options.abortSignal) {
    const abort = () => {
      disconnect();
    };
    if (options.abortSignal.aborted) {
      abort();
    } else {
      options.abortSignal.addEventListener("abort", abort, { once: true });
    }
  }

