import { resolveMarkdownTableMode } from "openclaw/plugin-sdk/config-runtime";
import { convertMarkdownTables } from "openclaw/plugin-sdk/text-runtime";
import { resolvePulseBoardAccount } from "./accounts.js";
import type { PulseBoardClient } from "./client.js";
import { connectPulseBoardClient, makePulseBoardMessageId } from "./client.js";
import { isBoardTarget, normalizePulseBoardMessagingTarget } from "./normalize.js";
import { getPulseBoardRuntime } from "./runtime.js";
import type { CoreConfig } from "./types.js";

type SendPulseBoardOptions = {
  cfg?: CoreConfig;
  accountId?: string;
  replyTo?: string;
  target?: string;
  client?: PulseBoardClient;
};

export type SendPulseBoardResult = {
  messageId: string;
  target: string;
};

function recordPulseBoardOutboundActivity(accountId: string): void {
  try {
    getPulseBoardRuntime().channel.activity.record({
      channel: "pulseboard",
      accountId,
      direction: "outbound",
    });
  } catch (error) {
    if (!(error instanceof Error) || error.message !== "PulseBoard runtime not initialized") {
      throw error;
    }
  }
}

function resolveTarget(to: string, opts?: SendPulseBoardOptions): string {
  const fromArg = normalizePulseBoardMessagingTarget(to);
  if (fromArg) {
    return fromArg;
  }
  const fromOpt = normalizePulseBoardMessagingTarget(opts?.target ?? "");
  if (fromOpt) {
    return fromOpt;
  }
  throw new Error(`Invalid PulseBoard target: ${to}`);
}

export async function sendMessagePulseBoard(
  to: string,
  text: string,
  opts: SendPulseBoardOptions = {},
): Promise<SendPulseBoardResult> {
  const runtime = getPulseBoardRuntime();
  const cfg = (opts.cfg ?? runtime.config.loadConfig()) as CoreConfig;
  const account = resolvePulseBoardAccount({
    cfg,
    accountId: opts.accountId,
  });

  if (!account.configured) {
    throw new Error(
      `PulseBoard is not configured for account "${account.accountId}" (need url, token, and username in channels.pulseboard).`,
    );
  }

  const target = resolveTarget(to, opts);
  const tableMode = resolveMarkdownTableMode({
    cfg,
    channel: "pulseboard",
    accountId: account.accountId,
  });
  const prepared = convertMarkdownTables(text.trim(), tableMode);
  const payload = opts.replyTo ? `${prepared}\n\n[reply:${opts.replyTo}]` : prepared;

  if (!payload.trim()) {
    throw new Error("Message must be non-empty for PulseBoard sends");
  }

  const isBoard = isBoardTarget(target);
  const client = opts.client;
  if (client?.isReady()) {
    if (isBoard) {
      client.sendToBoard(target, payload);
    } else {
      client.sendDm(target, payload);
    }
  } else {
    const transient = await connectPulseBoardClient({
      url: account.url,
      token: account.token,
      username: account.username,
      connectTimeoutMs: 12000,
    });
    if (isBoard) {
      transient.sendToBoard(target, payload);
    } else {
      transient.sendDm(target, payload);
    }
    transient.disconnect();
  }

  recordPulseBoardOutboundActivity(account.accountId);

  return {
    messageId: makePulseBoardMessageId(),
    target,
  };
}

