  label: "PulseBoard",
  channel,
  policyKey: "channels.pulseboard.dmPolicy",
  allowFromKey: "channels.pulseboard.allowFrom",
  getCurrent: (cfg) => (cfg as CoreConfig).channels?.pulseboard?.dmPolicy ?? "pairing",
  setPolicy: (cfg, policy) => setPulseBoardDmPolicy(cfg as CoreConfig, policy),
  promptAllowFrom: async ({ cfg, prompter, accountId }) =>
    await promptPulseBoardAllowFrom({
      cfg: cfg as CoreConfig,
      prompter,
      accountId,
    }),
};

export const pulseBoardSetupWizard: ChannelSetupWizard = {
  channel,
  status: createStandardChannelSetupStatus({
    channelLabel: "PulseBoard",
    configuredLabel: "configured",
    unconfiguredLabel: "needs url + token + username",
    configuredHint: "configured",
    unconfiguredHint: "needs url + token + username",
    configuredScore: 1,
    unconfiguredScore: 0,
    includeStatusLine: true,
    resolveConfigured: ({ cfg }) =>
      listPulseBoardAccountIds(cfg as CoreConfig).some(
        (accountId) =>
          resolvePulseBoardAccount({ cfg: cfg as CoreConfig, accountId }).configured,
      ),
  }),
  introNote: {
    title: "PulseBoard setup",
    lines: [
      "PulseBoard needs a server URL, an API token, and a bot username.",
      "Boards are group targets (e.g. #general); DMs use plain usernames (e.g. alice).",
      'Set channels.pulseboard.groupPolicy="allowlist" and channels.pulseboard.groups for tighter board control.',
      'Note: PulseBoard boards are mention-gated by default. To allow unmentioned replies, set channels.pulseboard.groups["#board"].requireMention=false (or "*" for all).',
      "Env vars supported: PULSEBOARD_URL, PULSEBOARD_TOKEN, PULSEBOARD_USERNAME, PULSEBOARD_BOARDS.",
      `Docs: ${formatDocsLink("/channels/pulseboard", "channels/pulseboard")}`,
    ],
    shouldShow: ({ cfg, accountId }) =>
      !resolvePulseBoardAccount({ cfg: cfg as CoreConfig, accountId }).configured,
  },
  prepare: async ({ cfg, accountId, credentialValues, prompter }) => {
    const resolved = resolvePulseBoardAccount({ cfg: cfg as CoreConfig, accountId });
    const isDefaultAccount = accountId === DEFAULT_ACCOUNT_ID;
    const envUrl = isDefaultAccount ? process.env.PULSEBOARD_URL?.trim() : "";
    const envToken = isDefaultAccount ? process.env.PULSEBOARD_TOKEN?.trim() : "";
    const envUsername = isDefaultAccount ? process.env.PULSEBOARD_USERNAME?.trim() : "";
    const envReady = Boolean(
      envUrl &&
        envToken &&
        envUsername &&
        !resolved.config.url &&
        !resolved.config.token &&
        !resolved.config.username,
    );

    if (envReady) {
      const useEnv = await prompter.confirm({
        message: "PULSEBOARD_URL, PULSEBOARD_TOKEN, and PULSEBOARD_USERNAME detected. Use env vars?",
        initialValue: true,
      });
      if (useEnv) {
        return {
          cfg: updatePulseBoardAccountConfig(cfg as CoreConfig, accountId, { enabled: true }),
          credentialValues: {
            ...credentialValues,
            [USE_ENV_FLAG]: "1",
          },
        };
      }
    }

    return {
      cfg: updatePulseBoardAccountConfig(cfg as CoreConfig, accountId, { enabled: true }),
      credentialValues: {
        ...credentialValues,
        [USE_ENV_FLAG]: "0",
      },
    };
  },
  credentials: [],
  textInputs: [
    {
      inputKey: "httpHost",
      message: "PulseBoard server URL",
      placeholder: "https://pb.example.com",
      currentValue: ({ cfg, accountId }) =>
        resolvePulseBoardAccount({ cfg: cfg as CoreConfig, accountId }).config.url || undefined,
      shouldPrompt: ({ credentialValues }) => credentialValues[USE_ENV_FLAG] !== "1",
      validate: ({ value }) => (String(value ?? "").trim() ? undefined : "Required"),
      normalizeValue: ({ value }) => String(value).trim(),
      applySet: async ({ cfg, accountId, value }) =>
        updatePulseBoardAccountConfig(cfg as CoreConfig, accountId, {
          enabled: true,
          url: value,
        }),
    },
    {
      inputKey: "token",
      message: "PulseBoard API token",
      currentValue: ({ cfg, accountId }) =>
        resolvePulseBoardAccount({ cfg: cfg as CoreConfig, accountId }).config.token || undefined,
      shouldPrompt: ({ credentialValues }) => credentialValues[USE_ENV_FLAG] !== "1",
      validate: ({ value }) => (String(value ?? "").trim() ? undefined : "Required"),
      normalizeValue: ({ value }) => String(value).trim(),
      applySet: async ({ cfg, accountId, value }) =>
        updatePulseBoardAccountConfig(cfg as CoreConfig, accountId, {
          enabled: true,
          token: value,
        }),
    },
    {
      inputKey: "userId",
      message: "PulseBoard username",
      currentValue: ({ cfg, accountId }) =>
        resolvePulseBoardAccount({ cfg: cfg as CoreConfig, accountId }).config.username || undefined,
      shouldPrompt: ({ credentialValues }) => credentialValues[USE_ENV_FLAG] !== "1",
      initialValue: ({ cfg, accountId }) =>
        resolvePulseBoardAccount({ cfg: cfg as CoreConfig, accountId }).config.username ||
        "openclaw",
      validate: ({ value }) => (String(value ?? "").trim() ? undefined : "Required"),
      normalizeValue: ({ value }) => String(value).trim(),
      applySet: async ({ cfg, accountId, value }) =>
        updatePulseBoardAccountConfig(cfg as CoreConfig, accountId, {
          enabled: true,
          username: value,
        }),
    },
    {
      inputKey: "groupChannels",
      message: "Auto-subscribe to PulseBoard boards (optional, comma-separated)",
      placeholder: "#general, #ops",
      required: false,
      applyEmptyValue: true,
      currentValue: ({ cfg, accountId }) =>
        resolvePulseBoardAccount({ cfg: cfg as CoreConfig, accountId }).config.boards?.join(", "),
      shouldPrompt: ({ credentialValues }) => credentialValues[USE_ENV_FLAG] !== "1",
      normalizeValue: ({ value }) =>
        parseListInput(String(value))
          .map((entry) => normalizeBoardEntry(entry))
          .filter((entry): entry is string => Boolean(entry && entry !== "*"))
          .filter((entry) => isBoardTarget(entry))
          .join(", "),
      applySet: async ({ cfg, accountId, value }) => {
        const boards = parseListInput(String(value))
          .map((entry) => normalizeBoardEntry(entry))
          .filter((entry): entry is string => Boolean(entry && entry !== "*"))
          .filter((entry) => isBoardTarget(entry));
        return updatePulseBoardAccountConfig(cfg as CoreConfig, accountId, {
          enabled: true,
          boards: boards.length > 0 ? boards : undefined,
        });
      },
    },
  ],
  groupAccess: {
    label: "PulseBoard boards",
    placeholder: "#general, #ops, *",
    currentPolicy: ({ cfg, accountId }) =>
      resolvePulseBoardAccount({ cfg: cfg as CoreConfig, accountId }).config.groupPolicy ??
      "allowlist",
    currentEntries: ({ cfg, accountId }) =>
      Object.keys(
        resolvePulseBoardAccount({ cfg: cfg as CoreConfig, accountId }).config.groups ?? {},
      ),
    updatePrompt: ({ cfg, accountId }) =>
      Boolean(
        resolvePulseBoardAccount({ cfg: cfg as CoreConfig, accountId }).config.groups,
      ),
    setPolicy: ({ cfg, accountId, policy }) =>
      setPulseBoardGroupAccess(
        cfg as CoreConfig,
        accountId,
        policy,
        [],
        normalizeBoardEntry,
      ),
    resolveAllowlist: async ({ entries }) =>
      [...new Set(entries.map((entry) => normalizeBoardEntry(entry)).filter(Boolean))] as string[],
    applyAllowlist: ({ cfg, accountId, resolved }) =>
      setPulseBoardGroupAccess(
        cfg as CoreConfig,
        accountId,
        "allowlist",
        resolved as string[],
        normalizeBoardEntry,
      ),
  },
  allowFrom: createAllowFromSection({
    helpTitle: "PulseBoard allowlist",
    helpLines: [
      "Allowlist PulseBoard DMs by sender username.",
      "Examples:",
      "- alice",
      "- @bob",
      "Multiple entries: comma-separated.",
    ],
    message: "PulseBoard allowFrom (username)",
    placeholder: "alice, @bob",
    invalidWithoutCredentialNote: "Use a PulseBoard username (e.g. alice or @alice).",
    parseId: (raw) => {
      const normalized = normalizePulseBoardAllowEntry(raw);
      return normalized || null;
    },
    apply: async ({ cfg, allowFrom }) => setPulseBoardAllowFrom(cfg as CoreConfig, allowFrom),
  }),
  finalize: async ({ cfg, accountId, prompter }) => {
    let next = cfg as CoreConfig;

    const resolvedAfterGroups = resolvePulseBoardAccount({ cfg: next, accountId });
    if (resolvedAfterGroups.config.groupPolicy === "allowlist") {
      const groupKeys = Object.keys(resolvedAfterGroups.config.groups ?? {});
      if (groupKeys.length > 0) {
        const wantsMentions = await prompter.confirm({
          message: "Require @mention to reply in PulseBoard boards?",
          initialValue: true,
        });
        if (!wantsMentions) {
          const groups = resolvedAfterGroups.config.groups ?? {};
          const patched = Object.fromEntries(
            Object.entries(groups).map(([key, value]) => [
              key,
              { ...value, requireMention: false },
            ]),
          );
          next = updatePulseBoardAccountConfig(next, accountId, { groups: patched });
        }
      }
    }

    return { cfg: next };
  },
  completionNote: {
    title: "PulseBoard next steps",
    lines: [
      "Next: restart gateway and verify status.",
      "Command: openclaw channels status --probe",
      `Docs: ${formatDocsLink("/channels/pulseboard", "channels/pulseboard")}`,
    ],
  },
  dmPolicy: pulseBoardDmPolicy,
  disable: (cfg) => setSetupChannelEnabled(cfg, channel, false),
};

export { pulseBoardSetupAdapter };

